const svg=$('#dual-svg'), out=$('#dual-out');
const buttons = {coll:$('#dual-coll'), incl:$('#dual-incl'), double:$('#dual-double')};
let mode='coll';

function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=620, H=320;
  // header bands
  svg.appendChild(Object.assign(SVG('text',{x:W/4,y:24,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'TOPOLOGY  (CHaus)'}));
  svg.appendChild(Object.assign(SVG('text',{x:3*W/4,y:24,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'C*-ALGEBRAS (cCAlg₁ᵒᵖ)'}));
  svg.appendChild(SVG('line',{x1:W/2,y1:20,x2:W/2,y2:H-20,stroke:'var(--line)','stroke-dasharray':'4,4'}));

  if(mode==='coll'){
    // left: Y = {a,b,c} → X = {*}
    drawNode(svg, 100, 100, 'a', {r:14,stroke:'var(--blue)'});
    drawNode(svg, 100, 160, 'b', {r:14,stroke:'var(--blue)'});
    drawNode(svg, 100, 220, 'c', {r:14,stroke:'var(--blue)'});
    drawNode(svg, 230, 160, '*', {r:14,stroke:'var(--green)'});
    drawArrow(svg, [115,100],[215,160],{color:'var(--mute)',markerId:'d-coll1'});
    drawArrow(svg, [115,160],[215,160],{color:'var(--mute)',markerId:'d-coll1'});
    drawArrow(svg, [115,220],[215,160],{color:'var(--mute)',markerId:'d-coll1'});
    svg.appendChild(Object.assign(SVG('text',{x:165,y:H-30,'text-anchor':'middle','font-size':12,fill:'var(--ink)'}),{textContent:'Y = {a,b,c}  →  X = {*},  φ(everything) = *'}));
    // right: C(X) = ℂ → C(Y) = ℂ³, constant map
    drawNode(svg, 410, 160, 'ℂ', {r:18,stroke:'var(--green)'});
    drawNode(svg, 540, 100, 'ℂ', {r:14,stroke:'var(--blue)'});
    drawNode(svg, 540, 160, 'ℂ', {r:14,stroke:'var(--blue)'});
    drawNode(svg, 540, 220, 'ℂ', {r:14,stroke:'var(--blue)'});
    drawArrow(svg, [428,160],[525,100],{color:'var(--violet)',markerId:'d-coll2',label:'φ*'});
    drawArrow(svg, [428,160],[525,160],{color:'var(--violet)',markerId:'d-coll2'});
    drawArrow(svg, [428,160],[525,220],{color:'var(--violet)',markerId:'d-coll2'});
    svg.appendChild(Object.assign(SVG('text',{x:475,y:H-30,'text-anchor':'middle','font-size':12,fill:'var(--ink)'}),{textContent:'C(X) = ℂ  →  C(Y) = ℂ³,  φ*(c) = (c,c,c)'}));
    out.textContent =
      `Topology: φ : Y={a,b,c} → X={*} is the unique map (collapse).\n`+
      `Algebra:  φ* : C(X)=ℂ → C(Y)=ℂ³, φ*(c) = constant c.\n`+
      `Note arrow direction reversal: a SURJECTION on the left becomes an INJECTION (in fact, the diagonal embedding ℂ ↪ ℂ³) on the right.`;
  } else if(mode==='incl'){
    // left: i : {1,2} ↪ {1,2,3}
    drawNode(svg, 90, 130, '1', {r:13,stroke:'var(--blue)'});
    drawNode(svg, 90, 200, '2', {r:13,stroke:'var(--blue)'});
    drawNode(svg, 230, 110, '1', {r:13,stroke:'var(--green)'});
    drawNode(svg, 230, 170, '2', {r:13,stroke:'var(--green)'});
    drawNode(svg, 230, 230, '3', {r:13,stroke:'var(--green)'});
    drawArrow(svg, [103,130],[218,110],{color:'var(--mute)',markerId:'d-incl1'});
    drawArrow(svg, [103,200],[218,170],{color:'var(--mute)',markerId:'d-incl1'});
    svg.appendChild(Object.assign(SVG('text',{x:165,y:H-30,'text-anchor':'middle','font-size':12,fill:'var(--ink)'}),{textContent:'i : Y={1,2} ↪ X={1,2,3}'}));
    // right: C(X)=ℂ³ → C(Y)=ℂ², restriction (drop coord 3)
    drawNode(svg, 410, 110, 'ℂ', {r:13,stroke:'var(--green)'});
    drawNode(svg, 410, 170, 'ℂ', {r:13,stroke:'var(--green)'});
    drawNode(svg, 410, 230, 'ℂ', {r:13,stroke:'var(--green)'});
    drawNode(svg, 540, 130, 'ℂ', {r:13,stroke:'var(--blue)'});
    drawNode(svg, 540, 200, 'ℂ', {r:13,stroke:'var(--blue)'});
    drawArrow(svg, [423,110],[527,130],{color:'var(--violet)',markerId:'d-incl2',label:'i*'});
    drawArrow(svg, [423,170],[527,200],{color:'var(--violet)',markerId:'d-incl2'});
    // x for the dropped one
    svg.appendChild(Object.assign(SVG('text',{x:475,y:240,'text-anchor':'middle','font-size':14,fill:'var(--pink)'}),{textContent:'×'}));
    svg.appendChild(Object.assign(SVG('text',{x:475,y:H-30,'text-anchor':'middle','font-size':12,fill:'var(--ink)'}),{textContent:'i* : ℂ³ ↠ ℂ², (a,b,c) ↦ (a,b)'}));
    out.textContent =
      `Topology: a closed inclusion {1,2} ↪ {1,2,3}.\n`+
      `Algebra: i* : C(X)=ℂ³ ↠ C(Y)=ℂ², "restrict to {1,2}".\n`+
      `Kernel: {(0,0,c) : c ∈ ℂ} = functions vanishing on Y. Closed inclusions ↔ quotient algebras.`;
  } else { // double cover
    // left: T → T,  z ↦ z²
    const cxL=130, cyL=160, RL=70;
    svg.appendChild(SVG('circle',{cx:cxL,cy:cyL,r:RL,fill:'none',stroke:'var(--blue)','stroke-width':1.5}));
    const cxR=270, cyR=160, RR=70;
    svg.appendChild(SVG('circle',{cx:cxR,cy:cyR,r:RR,fill:'none',stroke:'var(--green)','stroke-width':1.5}));
    // mark a base point and its preimages
    svg.appendChild(SVG('circle',{cx:cxR+RR,cy:cyR,r:5,fill:'var(--green)'}));
    svg.appendChild(SVG('circle',{cx:cxL+RL,cy:cyL,r:5,fill:'var(--yellow)'}));
    svg.appendChild(SVG('circle',{cx:cxL-RL,cy:cyL,r:5,fill:'var(--yellow)'}));
    drawArrow(svg, [cxL+8,cyL-RL-10],[cxR-8,cyR-RR-10],{color:'var(--mute)',markerId:'d-dbl1',curve:-20,label:'z↦z²'});
    svg.appendChild(Object.assign(SVG('text',{x:cxL,y:cyL+RL+22,'text-anchor':'middle','font-size':12,fill:'var(--ink)'}),{textContent:'Y = 𝕋'}));
    svg.appendChild(Object.assign(SVG('text',{x:cxR,y:cyR+RR+22,'text-anchor':'middle','font-size':12,fill:'var(--ink)'}),{textContent:'X = 𝕋'}));
    // right: C(T) → C(T), f(z) ↦ f(z²)  (pullback embeds even-Fourier subalgebra)
    const lx=410, rx=560, by=140;
    svg.appendChild(Object.assign(SVG('text',{x:lx,y:by-10,'text-anchor':'middle','font-size':13,fill:'var(--green)'}),{textContent:'C(X) = C(𝕋)'}));
    svg.appendChild(Object.assign(SVG('text',{x:rx,y:by-10,'text-anchor':'middle','font-size':13,fill:'var(--blue)'}),{textContent:'C(Y) = C(𝕋)'}));
    drawArrow(svg, [lx+30,by],[rx-30,by],{color:'var(--violet)',markerId:'d-dbl2',label:'φ*'});
    svg.appendChild(Object.assign(SVG('text',{x:(lx+rx)/2,y:by+44,'text-anchor':'middle','font-size':12,fill:'var(--ink)'}),{textContent:'φ*(f)(w) = f(w²)'}));
    svg.appendChild(Object.assign(SVG('text',{x:(lx+rx)/2,y:by+72,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'image = even Fourier modes  {f : f̂(2k+1)=0}'}));
    out.textContent =
      `Topology: φ : 𝕋 → 𝕋, z ↦ z² (degree-2 covering).\n`+
      `Algebra:  φ* : C(𝕋) → C(𝕋), f ↦ f∘φ.  Image is the subalgebra of functions g with g(z) = g(-z) — equivalently, only even Fourier coefficients.\n`+
      `Surjective covering  ↔  injective *-hom into a subalgebra. φ* is NOT surjective.`;
  }
  // big curved arrow on top showing functor reversal
  drawArrow(svg, [W/4-10, 50],[3*W/4-30, 50],{color:'var(--cyan)',markerId:'d-fun',curve:-15,label:'C(-)'});
  drawArrow(svg, [3*W/4-30, 70],[W/4-10, 70],{color:'var(--cyan)',markerId:'d-fun2',curve:15,label:'(-)^'});
}

Object.entries(buttons).forEach(([k,b])=> b.addEventListener('click', ()=>{
  mode = k;
  Object.values(buttons).forEach(x=>x.classList.remove('active'));
  b.classList.add('active');
  render();
}));
render();

