    sout.textContent = `θ = ${θ.toFixed(3)}`;
    const W=540, H=280;
    const rat = isRational(θ);

    // Visualize the unit-disc orbit of v u v* u* relation: angles e^{2πiθ}
    // left: a circle with two unitary generators u, v as rotations
    const cx=130, cy=140, R=90;
    svg.appendChild(SVG('circle',{cx,cy,r:R,fill:'none',stroke:'var(--line)','stroke-width':1.5}));
    // base point
    svg.appendChild(SVG('circle',{cx:cx+R,cy,r:4,fill:'var(--ink)'}));
    // orbit under multiplication by e^{2πiθ}
    const ORB=24;
    for(let k=0;k<ORB;k++){
      const ang = 2*Math.PI*θ*k;
      const x = cx + R*Math.cos(ang), y = cy - R*Math.sin(ang);
      const op = 1 - k/ORB*0.7;
      svg.appendChild(SVG('circle',{cx:x,cy:y,r:3.5,fill:'var(--yellow)','fill-opacity':op}));
    }
    svg.appendChild(Object.assign(SVG('text',{x:cx,y:cy+R+24,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'u-orbit of 1 ∈ 𝕋, step e^{2πiθ}'}));

    // right: status panel
    const rx=320, ry=80;
    svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry,'font-size':14,fill:'var(--ink)','font-weight':600}),{textContent:`A_θ generated by u, v with vu = e^{2πiθ} uv`}));
    if(θ===0){
      svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry+30,'font-size':13,fill:'var(--green)'}),{textContent:'θ = 0:  uv = vu, so A_0 ≅ C(𝕋²)'}));
      svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry+50,'font-size':13,fill:'var(--green)'}),{textContent:'classical spectrum = 𝕋² (the 2-torus)'}));
      out.textContent = `θ=0: A_θ is commutative, equals C(𝕋²). Gelfand spectrum = 𝕋².\nThis is the classical commutative endpoint of the family.`;
    } else if(rat){
      svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry+30,'font-size':13,fill:'var(--blue)'}),{textContent:`θ = ${rat.p}/${rat.q} (rational)`}));
      svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry+50,'font-size':13,fill:'var(--blue)'}),{textContent:`A_{p/q} = sections of an M_q-bundle over 𝕋²`}));
      svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry+70,'font-size':12,fill:'var(--mute)'}),{textContent:`center ≅ C(𝕋²); has ordinary spectrum = 𝕋² (with multiplicity)`}));
      out.textContent = `θ = ${rat.p}/${rat.q}:  A_θ is a homogeneous Azumaya-type algebra over the 2-torus.\nIt has a rich character/representation theory, but A_θ ≇ C(X) for any X — it is noncommutative.`;
    } else {
      svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry+30,'font-size':13,fill:'var(--pink)'}),{textContent:`θ = ${θ.toFixed(3)}  (irrational)`}));
      svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry+50,'font-size':13,fill:'var(--pink)'}),{textContent:'A_θ is simple, has a UNIQUE TRACE,'}));
      svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry+70,'font-size':13,fill:'var(--pink)'}),{textContent:'and has  Â = ∅  (no characters).'}));
      svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry+96,'font-size':12,fill:'var(--mute)'}),{textContent:'classical Gelfand machinery FAILS.'}));
      svg.appendChild(Object.assign(SVG('text',{x:rx,y:ry+114,'font-size':12,fill:'var(--mute)'}),{textContent:'still: K_0(A_θ) = ℤ + θℤ ⊂ ℝ (Pimsner–Voiculescu).'}));
      out.textContent = `θ irrational: A_θ is simple. Its only "spectrum" in the classical sense is empty.\nBut K-theory and trace pairings give it K_0(A_θ) = ℤ + θℤ as an ordered subgroup of ℝ — Connes's first triumph for noncommutative geometry.\nThis is the prototypical noncommutative space: orbit space of the irrational rotation 𝕋 ↻ 𝕋, which is a horrible topological quotient but a perfectly good C*-algebra.`;
    }
  }

  sl.addEventListener('input', render);
  render();
})();

