const svg=$('#dcom-svg'), out=$('#dcom-out');
const bD=$('#dcom-diag'), bB=$('#dcom-block'), bS=$('#dcom-scalar');
let mode='diag';
function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=560, H=240, col=[90,280,470], y=120, r=46;
  const labels=['M','M′','M′′'];
  const colors=['var(--yellow)','var(--blue)','var(--green)'];
  let desc, ms;
  if(mode==='diag'){
    ms=['diag(a,b,c)','diag(x,y,z)','diag(a,b,c)'];
    desc='M = diagonal matrices (dim 3). Abelian, maximal abelian — so M′ = M, hence M′′ = M. A von Neumann algebra.';
  } else if(mode==='block'){
    ms=['a⊕1 ⊕ B₂₂','diag(x,x,y)','a⊕1 ⊕ B₂₂'];
    desc='M = {λ·1 on ⟨e₁⟩} ⊕ M_2(ℂ) on ⟨e₂,e₃⟩, dim 5. M′ = scalars on each block = ℂ·1 ⊕ ℂ·1, dim 2. M′′ = M. von Neumann algebra.';
  } else {
    ms=['λ·1','all of M₃(ℂ)','λ·1'];
    desc='M = ℂ·1 (centre), dim 1. M′ = everything commuting with 1 = M₃(ℂ), dim 9. M′′ = scalars, dim 1. Again M = M′′.';
  }
  for(let i=0;i<3;i++){
    svg.appendChild(SVG('circle',{cx:col[i],cy:y,r,fill:'none',stroke:colors[i],'stroke-width':2}));
    svg.appendChild(Object.assign(SVG('text',{x:col[i],y:y-r-10,'text-anchor':'middle','font-size':14,fill:colors[i],'font-weight':600}),{textContent:labels[i]}));
    svg.appendChild(Object.assign(SVG('text',{x:col[i],y:y+5,'text-anchor':'middle','font-size':12,fill:'var(--ink)'}),{textContent:ms[i]}));
  }
  // arrows M -> M' -> M'' and equality M == M''
  drawArrow(svg,[col[0]+r,y],[col[1]-r,y],{color:'var(--mute)',label:"'",markerId:'dc-a1'});
  drawArrow(svg,[col[1]+r,y],[col[2]-r,y],{color:'var(--mute)',label:"'",markerId:'dc-a2'});
  svg.appendChild(Object.assign(SVG('text',{x:(col[0]+col[2])/2,y:y+r+30,'text-anchor':'middle','font-size':13,fill:'var(--green)'}),{textContent:'M = M′′   (double commutant theorem)'}));
  out.textContent = desc;
}
function set(m,btn){ mode=m; [bD,bB,bS].forEach(b=>b.classList.remove('active')); btn.classList.add('active'); render(); }
bD.addEventListener('click',()=>set('diag',bD));
bB.addEventListener('click',()=>set('block',bB));
bS.addEventListener('click',()=>set('scalar',bS));
render();

