const svg=$('#typ-svg'), out=$('#typ-out');
const btns={In:$('#typ-In'),Iinf:$('#typ-Iinf'),II1:$('#typ-II1'),IIinf:$('#typ-IIinf'),III:$('#typ-III')};
const data={
  In:{label:'I_n',trace:'unique trace, integer-valued on projections',range:'{0,1,…,n}',ex:'M_n(ℂ) acting on ℂⁿ.',color:'var(--yellow)'},
  Iinf:{label:'I_∞',trace:'semi-finite trace (= usual operator trace)',range:'{0,1,2,…,∞}',ex:'B(H), H separable ∞-dim.',color:'var(--yellow)'},
  II1:{label:'II_1',trace:'unique faithful finite trace τ, τ(1)=1',range:'[0,1] — continuous!',ex:'hyperfinite factor ℛ = (⊗_n M_2)″; free group factors L(F_n).',color:'var(--green)'},
  IIinf:{label:'II_∞',trace:'semi-finite unbounded trace',range:'[0,∞]',ex:'ℛ ⊗̄ B(H).',color:'var(--green)'},
  III:{label:'III',trace:'NO semi-finite trace',range:'{0,∞} — every nonzero proj is infinite',ex:'local algebras in QFT; Powers factors R_λ (0<λ<1).',color:'var(--pink)'}
};
let cur='In';
function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=560, H=260;
  // draw a number-line of projection dimensions for the current type
  const x0=60, x1=500, y0=80;
  svg.appendChild(SVG('line',{x1:x0,y1:y0,x2:x1,y2:y0,stroke:'var(--line)','stroke-width':1.5}));
  svg.appendChild(Object.assign(SVG('text',{x:x0,y:y0+22,'text-anchor':'middle','font-size':11,fill:'var(--mute)'}),{textContent:'0'}));
  svg.appendChild(Object.assign(SVG('text',{x:x1,y:y0+22,'text-anchor':'middle','font-size':11,fill:'var(--mute)'}),{textContent: (cur==='II1'?'1':'∞')}));
  const d=data[cur];
  if(cur==='In'){
    const n=5;
    for(let k=0;k<=n;k++){
      const x = x0 + (x1-x0)*k/n;
      svg.appendChild(SVG('circle',{cx:x,cy:y0,r:5,fill:d.color}));
      svg.appendChild(Object.assign(SVG('text',{x,y:y0-12,'text-anchor':'middle','font-size':10,fill:'var(--mute)'}),{textContent:k}));
    }
  } else if(cur==='Iinf'){
    for(let k=0;k<=12;k++){
      const x = x0 + (x1-x0)*k/14;
      svg.appendChild(SVG('circle',{cx:x,cy:y0,r:4,fill:d.color}));
    }
    svg.appendChild(Object.assign(SVG('text',{x:x0+(x1-x0)*13.5/14,y:y0+4,'text-anchor':'middle','font-size':14,fill:'var(--mute)'}),{textContent:'…'}));
  } else if(cur==='II1'){
    svg.appendChild(SVG('rect',{x:x0,y:y0-6,width:x1-x0,height:12,fill:d.color,'fill-opacity':0.55,stroke:d.color}));
  } else if(cur==='IIinf'){
    svg.appendChild(SVG('rect',{x:x0,y:y0-6,width:x1-x0-18,height:12,fill:d.color,'fill-opacity':0.55,stroke:d.color}));
    svg.appendChild(Object.assign(SVG('text',{x:x1-6,y:y0+4,'text-anchor':'middle','font-size':14,fill:'var(--mute)'}),{textContent:'…'}));
  } else {
    svg.appendChild(SVG('circle',{cx:x0,cy:y0,r:5,fill:d.color}));
    svg.appendChild(SVG('circle',{cx:x1,cy:y0,r:5,fill:d.color}));
    svg.appendChild(Object.assign(SVG('text',{x:(x0+x1)/2,y:y0+4,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'no intermediate projection dimensions'}));
  }
  svg.appendChild(Object.assign(SVG('text',{x:W/2,y:140,'text-anchor':'middle','font-size':14,fill:d.color,'font-weight':600}),{textContent:`type ${d.label}`}));
  svg.appendChild(Object.assign(SVG('text',{x:W/2,y:168,'text-anchor':'middle','font-size':12,fill:'var(--ink)'}),{textContent:`trace: ${d.trace}`}));
  svg.appendChild(Object.assign(SVG('text',{x:W/2,y:190,'text-anchor':'middle','font-size':12,fill:'var(--ink)'}),{textContent:`range of dim(p): ${d.range}`}));
  svg.appendChild(Object.assign(SVG('text',{x:W/2,y:220,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:`example: ${d.ex}`}));
  out.textContent = `Type ${d.label}. ${d.trace}. Projection dimensions live in ${d.range}.\nPrototype: ${d.ex}`;
}
function set(k){ cur=k; Object.keys(btns).forEach(x=>btns[x].classList.toggle('active',x===k)); render(); }
Object.keys(btns).forEach(k=>btns[k].addEventListener('click',()=>set(k)));
render();

