/* =============================== §11 Murray–vN widget =============================== */
(function(){
  const sl=$('#mvn-d'), sout=$('#mvn-d-out'), svg=$('#mvn-svg'), out=$('#mvn-out');
  function render(){
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    const d=(+sl.value)/100;
    sout.textContent = `d = ${d.toFixed(2)}`;
    const W=560, H=240;
    // two circles representing projections p, q; arcs showing their "dimensions"
    function wedge(cx,cy,R,frac,color,label){
      svg.appendChild(SVG('circle',{cx,cy,r:R,fill:'none',stroke:'var(--line)','stroke-width':1.5}));
      const a = 2*Math.PI*frac;
      const x2 = cx + R*Math.sin(a);
      const y2 = cy - R*Math.cos(a);
      const large = frac>0.5?1:0;
      const path = `M${cx} ${cy} L${cx} ${cy-R} A${R} ${R} 0 ${large} 1 ${x2} ${y2} Z`;
      svg.appendChild(SVG('path',{d:path,fill:color,'fill-opacity':0.55,stroke:color}));
      svg.appendChild(Object.assign(SVG('text',{x:cx,y:cy+R+22,'text-anchor':'middle','font-size':13,fill:color,'font-weight':600}),{textContent:label}));
    }
    wedge(150,120,70,d,'var(--yellow)','p (τ(p)='+d.toFixed(2)+')');
    wedge(410,120,70,d,'var(--blue)','q (τ(q)='+d.toFixed(2)+')');
    // arrow labelled v
    drawArrow(svg,[220,120],[340,120],{color:'var(--green)',label:'v',markerId:'mvn-v'});
    svg.appendChild(Object.assign(SVG('text',{x:280,y:108,'text-anchor':'middle','font-size':13,fill:'var(--green)','font-weight':600}),{textContent:'v: pH → qH'}));
    svg.appendChild(Object.assign(SVG('text',{x:280,y:148,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'v*v = p,  vv* = q'}));
    out.textContent = `Two projections with τ(p) = τ(q) = ${d.toFixed(2)} are Murray–von Neumann equivalent in a II₁ factor.\nA partial isometry v ∈ M witnesses the equivalence: v*v = p, vv* = q.\nThe dimension function d(p) = τ(p) takes every value in [0,1] — projections exist at ANY fraction.`;
  }
  sl.addEventListener('input',render);
  render();
})();

