  const V=[[260,50],[90,260],[430,260]];
  function bary(p1,p2,p3){
    return [V[0][0]*p1+V[1][0]*p2+V[2][0]*p3, V[0][1]*p1+V[1][1]*p2+V[2][1]*p3];
  }
  function render(){
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    let p1=(+sa.value)/100, p2=(+sb.value)/100;
    if(p1+p2>1){ const s=p1+p2; p1/=s+1e-9; p2/=s+1e-9; }
    const p3=Math.max(0,1-p1-p2);
    // triangle
    svg.appendChild(SVG('polygon',{points:V.map(v=>v.join(',')).join(' '),fill:'var(--panel2)',stroke:'var(--line)','stroke-width':1.5}));
    // vertices = pure states
    const names=['δ₁ (= ev₁)','δ₂ (= ev₂)','δ₃ (= ev₃)'];
    const colors=['var(--yellow)','var(--blue)','var(--green)'];
    for(let i=0;i<3;i++){
      svg.appendChild(SVG('circle',{cx:V[i][0],cy:V[i][1],r:7,fill:colors[i]}));
      const off=i===0?[-8,-14]:i===1?[-14,18]:[14,18];
      svg.appendChild(Object.assign(SVG('text',{x:V[i][0]+off[0],y:V[i][1]+off[1],'font-size':12,fill:colors[i]}),{textContent:names[i]}));
    }
    // draw the selected state as a point
    const [x,y]=bary(p1,p2,p3);
    svg.appendChild(SVG('circle',{cx:x,cy:y,r:8,fill:'var(--pink)',stroke:'#fff','stroke-width':1.5}));
    svg.appendChild(Object.assign(SVG('text',{x:x+12,y:y+4,'font-size':12,fill:'var(--pink)'}),{textContent:'φ'}));
    // label
    svg.appendChild(Object.assign(SVG('text',{x:260,y:290,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'S(A) = probability simplex Δ² ⊂ ℝ³'}));
    const isExtreme = (p1>0.98)||(p2>0.98)||(p3>0.98);
    out.textContent =
      `State: φ = ${p1.toFixed(2)}·δ₁ + ${p2.toFixed(2)}·δ₂ + ${p3.toFixed(2)}·δ₃.\n`+
      `${isExtreme?'PURE STATE — extreme point of S(A). Corresponds to a point of X = {1,2,3}.':'Mixed state — a proper convex combination of pure states. Not extreme.'}\n`+
