const svg=$('#gns-svg'), out=$('#gns-out');
const bT=$('#gns-tr'), bV=$('#gns-v'), bM=$('#gns-mix');
let mode='tr';
function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=560, H=260;
  // left: the state; right: its GNS rep
  svg.appendChild(SVG('rect',{x:30,y:40,width:200,height:180,rx:10,fill:'var(--panel2)',stroke:'var(--line)'}));
  svg.appendChild(SVG('rect',{x:330,y:40,width:200,height:180,rx:10,fill:'var(--panel2)',stroke:'var(--line)'}));
  svg.appendChild(Object.assign(SVG('text',{x:130,y:30,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'state ω on A = M_2(ℂ)'}));
  svg.appendChild(Object.assign(SVG('text',{x:430,y:30,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'GNS rep (π_ω, H_ω, Ω_ω)'}));
  let desc, right1, right2, right3;
  if(mode==='tr'){
    svg.appendChild(Object.assign(SVG('text',{x:130,y:90,'text-anchor':'middle','font-size':13,fill:'var(--ink)'}),{textContent:'ω(a) = ½ tr(a)'}));
    svg.appendChild(Object.assign(SVG('text',{x:130,y:120,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'faithful tracial state'}));
    right1='H_ω = ℂ⁴ (= M_2 with HS inner prod)';
    right2='π_ω(a) = left multiplication';
    right3='Ω_ω = 1/√2 · I';
    desc='The trace ½ tr is faithful, so N_ω = 0. Then A/N_ω = M_2(ℂ) with inner product ⟨a,b⟩ = ½ tr(b*a) — the Hilbert–Schmidt inner product. π_ω is left-regular rep; Ω_ω = I/√2. This rep is NOT irreducible (it decomposes as 2 copies of the defining rep).';
  } else if(mode==='v'){
    svg.appendChild(Object.assign(SVG('text',{x:130,y:90,'text-anchor':'middle','font-size':13,fill:'var(--ink)'}),{textContent:'ω_e(a) = ⟨ae, e⟩,  e ∈ ℂ²'}));
    svg.appendChild(Object.assign(SVG('text',{x:130,y:120,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'pure vector state (unit e)'}));
    right1='H_ω = ℂ²';
    right2='π_ω = identity rep of M_2 on ℂ²';
    right3='Ω_ω = e';
    desc='A unit vector e in ℂ² gives a pure state ω_e. The null ideal is N_ω = {a : ae=0}. The GNS space is M_2·e ≅ ℂ², π_ω is the defining rep, Ω_ω = e. This rep IS irreducible — pure state ↔ irreducible GNS (general theorem).';
  } else {
    svg.appendChild(Object.assign(SVG('text',{x:130,y:90,'text-anchor':'middle','font-size':13,fill:'var(--ink)'}),{textContent:'ω = ½ ω_{e₁} + ½ ω_{e₂}'}));
    svg.appendChild(Object.assign(SVG('text',{x:130,y:120,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'= ½ tr  (by coincidence in M_2)'}));
    right1='H_ω = ℂ² ⊕ ℂ²';
    right2='π_ω = id ⊕ id';
    right3='Ω_ω = (e₁,e₂)/√2';
    desc='A proper mixture of two pure states. GNS gives the direct sum of the two irreducible GNS reps — reducible. The cyclic vector is the "diagonal" √½(e₁,e₂). In M_2(ℂ) this mixture happens to equal ½ tr, but its GNS rep is distinct from the tracial one (Hilbert space has dim 4 either way but the algebras act differently — they differ by a unitary equivalence).';
  }
  svg.appendChild(Object.assign(SVG('text',{x:430,y:90,'text-anchor':'middle','font-size':13,fill:'var(--green)'}),{textContent:right1}));
  svg.appendChild(Object.assign(SVG('text',{x:430,y:120,'text-anchor':'middle','font-size':13,fill:'var(--green)'}),{textContent:right2}));
  svg.appendChild(Object.assign(SVG('text',{x:430,y:150,'text-anchor':'middle','font-size':13,fill:'var(--green)'}),{textContent:right3}));
  svg.appendChild(Object.assign(SVG('text',{x:430,y:188,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'ω(a) = ⟨Ω_ω, π_ω(a) Ω_ω⟩'}));
  drawArrow(svg,[235,130],[325,130],{color:'var(--blue)',label:'GNS',markerId:'gns-ar'});
  out.textContent = desc;
}
function set(m,b){ mode=m; [bT,bV,bM].forEach(x=>x.classList.remove('active')); b.classList.add('active'); render(); }
bT.addEventListener('click',()=>set('tr',bT));
bV.addEventListener('click',()=>set('v',bV));
bM.addEventListener('click',()=>set('mix',bM));
render();

