/* =============================== §15 approximate-unit widget =============================== */
(function(){
  const sl=$('#au-n'), sout=$('#au-n-out'), svg=$('#au-svg'), out=$('#au-out');
  function render(){
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    const n=+sl.value;
    sout.textContent = `n = ${n}`;
    const W=560, H=240, pad=30, y0=H-40;
    // axes
    svg.appendChild(SVG('line',{x1:pad,y1:y0,x2:W-pad,y2:y0,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:W/2,y1:20,x2:W/2,y2:y0,stroke:'var(--line)','stroke-dasharray':'3,3'}));
    // x in [-10,10]
    const xToPx = x => pad + (x+10)/20*(W-2*pad);
    const yToPx = y => y0 - y*160;
    // target f(x) = exp(-x^2/8) (a function in C_0(ℝ))
    const f = x=>Math.exp(-x*x/8);
    // approximate unit e_n: bump = 1 on [-n,n], smooth ramp to 0 on [-(n+1),-n] and [n,n+1]
    function e(x){
      const a=Math.abs(x);
      if(a<=n) return 1;
      if(a>=n+1) return 0;
      const t=a-n; return 1 - t*t*(3-2*t); // smoothstep
    }
    // draw f
    let d1='M';
    for(let k=0;k<=200;k++){ const x=-10+20*k/200; d1 += `${xToPx(x)} ${yToPx(f(x))} L`; }
    d1 = d1.slice(0,-1);
    svg.appendChild(SVG('path',{d:d1,fill:'none',stroke:'var(--blue)','stroke-width':1.8}));
    // draw e_n
    let d2='M';
    for(let k=0;k<=200;k++){ const x=-10+20*k/200; d2 += `${xToPx(x)} ${yToPx(e(x))} L`; }
    d2=d2.slice(0,-1);
    svg.appendChild(SVG('path',{d:d2,fill:'none',stroke:'var(--yellow)','stroke-width':1.8,'stroke-dasharray':'5,3'}));
    // draw e_n · f
    let d3='M';
    for(let k=0;k<=200;k++){ const x=-10+20*k/200; d3 += `${xToPx(x)} ${yToPx(e(x)*f(x))} L`; }
    d3=d3.slice(0,-1);
    svg.appendChild(SVG('path',{d:d3,fill:'none',stroke:'var(--green)','stroke-width':1.8}));
    // legend
    svg.appendChild(Object.assign(SVG('text',{x:W-pad-20,y:40,'text-anchor':'end','font-size':12,fill:'var(--blue)'}),{textContent:'f(x) = e^{-x²/8}'}));
    svg.appendChild(Object.assign(SVG('text',{x:W-pad-20,y:58,'text-anchor':'end','font-size':12,fill:'var(--yellow)'}),{textContent:`e_n(x)  (bump on [-${n},${n}])`}));
    svg.appendChild(Object.assign(SVG('text',{x:W-pad-20,y:76,'text-anchor':'end','font-size':12,fill:'var(--green)'}),{textContent:'(e_n · f)(x)'}));
    // sup-norm error
    let err=0;
    for(let k=0;k<=200;k++){ const x=-10+20*k/200; err=Math.max(err,Math.abs(f(x)-e(x)*f(x))); }
    out.textContent = `‖e_n · f − f‖_∞ ≈ ${err.toExponential(2)}  (→ 0 as n→∞).\nThis is what "approximate unit" means: no single element acts as the identity, but the net (e_n) approaches it on every compact set.`;
  }
  sl.addEventListener('input',render);
  render();
})();

