function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=620, H=320, midX=W/2;
  svg.appendChild(SVG('line',{x1:midX,y1:20,x2:midX,y2:H-20,stroke:'var(--line)','stroke-dasharray':'4,4'}));
  svg.appendChild(Object.assign(SVG('text',{x:W/4,y:24,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'Â  (Gelfand)'}));
  svg.appendChild(Object.assign(SVG('text',{x:3*W/4,y:24,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'Spec R  (Grothendieck)'}));

  if(mode==='Z'){
    // left: A = C({1,2,3}), three points
    svg.appendChild(Object.assign(SVG('text',{x:W/4,y:60,'text-anchor':'middle','font-size':13,fill:'var(--ink)'}),{textContent:'A = C({1,2,3}) ≅ ℂ³'}));
    const ys = [120,180,240];
    ['1','2','3'].forEach((lab,i)=>{
      svg.appendChild(SVG('circle',{cx:W/4, cy:ys[i], r:9, fill:'var(--yellow)'}));
      svg.appendChild(Object.assign(SVG('text',{x:W/4+18,y:ys[i]+4,'font-size':12,fill:'var(--ink)'}),{textContent:`ev_${lab} = (a₁,a₂,a₃)↦a_${lab}`}));
    });
    svg.appendChild(Object.assign(SVG('text',{x:W/4,y:280,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'all points are closed; |Â| = 3'}));

    // right: Spec ℤ — primes 2,3,5,7,... and (0) generic
    svg.appendChild(Object.assign(SVG('text',{x:3*W/4,y:60,'text-anchor':'middle','font-size':13,fill:'var(--ink)'}),{textContent:'R = ℤ'}));
    const primes=[2,3,5,7,11,13];
    primes.forEach((p,i)=>{
      const x = midX + 70 + i*38;
      svg.appendChild(SVG('circle',{cx:x,cy:170,r:7,fill:'var(--blue)'}));
      svg.appendChild(Object.assign(SVG('text',{x,y:188,'text-anchor':'middle','font-size':11,fill:'var(--mute)'}),{textContent:`(${p})`}));
    });
    svg.appendChild(Object.assign(SVG('text',{x:midX+70 + 6*38 + 10, y:174,'font-size':12,fill:'var(--mute)'}),{textContent:'…'}));
    // generic point (0) drawn as a fat fuzzy bar across
    svg.appendChild(SVG('rect',{x:midX+50, y:240, width:300, height:18, fill:'var(--violet)','fill-opacity':0.25, stroke:'var(--violet)','stroke-dasharray':'3,3'}));
    svg.appendChild(Object.assign(SVG('text',{x:midX+200,y:252,'text-anchor':'middle','font-size':12,fill:'var(--violet)'}),{textContent:'(0) — generic point, dense in Spec ℤ'}));
    svg.appendChild(Object.assign(SVG('text',{x:3*W/4,y:280,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'closed points + 1 generic point;  topology cofinite'}));

    out.textContent =
      `Gelfand: Â consists of three closed points, namely ev_1, ev_2, ev_3 — one per point of {1,2,3}. There is NO "generic" character.\n\n`+
      `Grothendieck: Spec ℤ has one closed point per prime p (the maximal ideal (p)), plus a single GENERIC POINT (0) that is dense.\n`+
      `The generic point is invisible to Gelfand because A/(0) would have to be a complex Banach division algebra with the C*-axioms — Gelfand–Mazur forces it to be ℂ, killing non-maximal ideals.`;
  } else {
    // A = C(T)
    svg.appendChild(Object.assign(SVG('text',{x:W/4,y:60,'text-anchor':'middle','font-size':13,fill:'var(--ink)'}),{textContent:'A = C(𝕋)'}));
    const cx=W/4, cy=180, R=70;
    svg.appendChild(SVG('circle',{cx,cy,r:R,fill:'none',stroke:'var(--yellow)','stroke-width':1.5}));
    // mark sample points
    for(let k=0;k<8;k++){
      const a = k/8 * 2*Math.PI;
      svg.appendChild(SVG('circle',{cx:cx+R*Math.cos(a), cy:cy-R*Math.sin(a), r:3.5,fill:'var(--yellow)'}));
    }
    svg.appendChild(Object.assign(SVG('text',{x:cx,y:cy+R+30,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'Â = 𝕋, all closed; uncountably many points, no generic point'}));

    // R = C[x]
    svg.appendChild(Object.assign(SVG('text',{x:3*W/4,y:60,'text-anchor':'middle','font-size':13,fill:'var(--ink)'}),{textContent:'R = ℂ[x]'}));
    // affine line: closed points = (x - a) for a ∈ ℂ — draw a small grid; plus generic (0)
    const Lx=midX+50, Rx=midX+300, Ly=160;
    svg.appendChild(SVG('line',{x1:Lx,y1:Ly,x2:Rx,y2:Ly,stroke:'var(--line)'}));
    // sample closed points
    [-2,-1,0,1,2,3].forEach(a => {
      const x = Lx + (a+2)*((Rx-Lx)/5);
      svg.appendChild(SVG('circle',{cx:x,cy:Ly,r:5,fill:'var(--blue)'}));
      svg.appendChild(Object.assign(SVG('text',{x,y:Ly+18,'text-anchor':'middle','font-size':11,fill:'var(--mute)'}),{textContent:`(x-${a})`}));
    });
    // generic point — dense bar
    svg.appendChild(SVG('rect',{x:Lx, y:Ly+40, width:Rx-Lx, height:18, fill:'var(--violet)','fill-opacity':0.25,stroke:'var(--violet)','stroke-dasharray':'3,3'}));
    svg.appendChild(Object.assign(SVG('text',{x:(Lx+Rx)/2,y:Ly+52,'text-anchor':'middle','font-size':12,fill:'var(--violet)'}),{textContent:'(0) — generic point of 𝔸¹_ℂ'}));
    svg.appendChild(Object.assign(SVG('text',{x:3*W/4,y:cy+R+30,'text-anchor':'middle','font-size':12,fill:'var(--mute)'}),{textContent:'closed pts ↔ ℂ, plus 1 generic point;  topology cofinite'}));

    out.textContent =
      `Gelfand: Â = 𝕋 (compact Hausdorff). Every character is ev_{e^{iθ}} for some θ.\n\n`+
      `Grothendieck: Spec ℂ[x] = 𝔸¹_ℂ has one closed point per a ∈ ℂ (the prime (x-a)) PLUS one generic point (0) which is dense.\n`+
      `Note: the topological spaces Â and Spec ℂ[x] are completely different — Â is Hausdorff and uncountable in a "geometric" sense, Spec ℂ[x] is non-Hausdorff with cofinite topology and only encodes geometry through its structure sheaf 𝒪.`;
  }
}

bZ.addEventListener('click', ()=>{ mode='Z'; bZ.classList.add('active'); bC.classList.remove('active'); render(); });
bC.addEventListener('click', ()=>{ mode='Cx'; bC.classList.add('active'); bZ.classList.remove('active'); render(); });
render();

